// src/components/CartItem/index.jsx (Предполагаемая структура)

import React from 'react';
import { useDispatch } from 'react-redux';
import { 
    incrementItem, // 🔑 ИСПРАВЛЕНО
    decrementItem,  // 🔑 ИСПРАВЛЕНО
    removeFromCart 
} from '../../store/slices/cartSlice';
import { getImageUrl } from '../../utils/api'; // Предполагаемый импорт
import s from './CartItem.module.css'; // Ваш файл стилей

const CartItem = ({ id, title, price, image, discont_price, quantity }) => {
    const dispatch = useDispatch();

    const handleIncrease = () => {
      dispatch(incrementItem(id)); // ✅ ИСПОЛЬЗУЕМ incrementItem
    };

    const handleDecrease = () => {
      dispatch(decrementItem(id)); // ✅ ИСПОЛЬЗУЕМ decrementItem
    };

    const handleRemove = () => {
        dispatch(removeFromCart(id));
    };

    const finalPrice = discont_price !== null ? discont_price : price;
    const totalItemPrice = (finalPrice * quantity).toFixed(2);

    return (
        <div className={s.item}>
            <img src={getImageUrl(image)} alt={title} className={s.image} />
            <div className={s.details}>
                <h3 className={s.title}>{title}</h3>

                <div className={s.priceBlock}>
                    <p className={s.finalPrice}>${totalItemPrice}</p>
                    <p className={s.unitPrice}>${finalPrice.toFixed(2)} / item</p>
                </div>

                <div className={s.controls}>
                    {/* Кнопка удаления */}
                    <button onClick={handleRemove} className={s.removeButton}>
                        &times;
                    </button>

                    {/* Счетчик */}
                    <div className={s.quantityCounter}>
                        <button onClick={handleDecrease} className={s.countButton}>—</button>
                        <span className={s.countValue}>{quantity}</span>
                        <button onClick={handleIncrease} className={s.countButton}>+</button>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default CartItem;
